function h(){const s=document.querySelectorAll(".counter__value");if(!s.length)return;const l=e=>{const r=e.textContent.trim().replace(",","."),t=parseFloat(r);if(Number.isNaN(t))return;const a=!Number.isInteger(t),i=Math.round(2e3/(1e3/60));let n=0;const d=o=>1-Math.pow(1-o,4),u=()=>{n++;const o=d(n/i),c=t*o;e.textContent=a?c.toFixed(1):Math.round(c),n<i?requestAnimationFrame(u):e.textContent=a?t.toFixed(1):t};requestAnimationFrame(u)},m={root:null,threshold:.25},f=new IntersectionObserver((e,r)=>{e.forEach(t=>{t.isIntersecting&&(l(t.target),r.unobserve(t.target))})},m);s.forEach(e=>f.observe(e))}export{h as initDigitsCounter};
